SELECT NVL(SUM(req_cnt), 0) AS req_cnt, NVL(SUM(reg_cnt), 0) AS reg_cnt, NVL(SUM(ing_cnt), 0) AS ing_cnt, NVL(SUM(cmp_cnt), 0) AS cmp_cnt, NVL(SUM(req_cnt) + SUM(reg_cnt) + SUM(ing_cnt) + SUM(cmp_cnt), 0) AS sum_cnt FROM ( SELECT NVL(DECODE(request_state, '0', COUNT(request_state)), 0) AS req_cnt, NVL(DECODE(request_state, '1', COUNT(request_state)), 0) AS reg_cnt, NVL(DECODE(request_state, '2', COUNT(request_state)), 0) AS ing_cnt, NVL(DECODE(request_state, '3', COUNT(request_state)), 0) AS cmp_cnt FROM CMS_BOARD WHERE manage_idx = 563 AND category1 = #{code_id}
AND category2 = #{homepage_id}
AND TO_CHAR(add_date, 'yyyy-MM-dd') >= #{start_date} AND TO_CHAR(add_date, 'yyyy-MM-dd') <= #{end_date}
AND delete_yn = 'N' AND parent_idx = 0 GROUP BY request_state )
